1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with 0 neighbors — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 (Underpopulation): two adjacent cells with 1 neighbor each die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 (Survival): middle cell of a row of 3 has 2 neighbors and survives — [(0,0),(1,0),(2,0)] result includes (1,0)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("Rule 3 (Overpopulation): center cell of full 3x3 block has 8 neighbors and dies", () => {
19	    const cells: Cell[] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(cells);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it("Rule 4 (Reproduction): dead cell (1,1) with exactly 3 neighbors becomes alive — [(0,0),(1,0),(0,1)] → result contains (1,1)", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
