export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCells = new Set(cells.map(cellKey));

  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
      liveCells.has(cellKey([x + dx, y + dy]))
    ).length;

  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(cellKey([x, y]), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      candidates.set(cellKey(neighbor), neighbor);
    }
  }

  return [...candidates.values()].filter((cell) => {
    const n = countLiveNeighbors(cell);
    return liveCells.has(cellKey(cell)) ? survives(n) : isBorn(n);
  });
}

