export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCells = new Set(cells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key);
      if (entry) {
        entry.count += 1;
      } else {
        neighborCounts.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  return [...neighborCounts.values()]
    .filter(({ cell, count }) =>
      liveCells.has(cellKey(cell)) ? survives(count) : isBorn(count)
    )
    .map(({ cell }) => cell);
}

